content.text:
`while` dövrünün sintaksisi belədir:
while (condition) {
  // icra olunacaq kod
}
- **Şərt (condition)**: Hər təkrarlamadan əvvəl yoxlanılır. Şərt doğru olarsa, kod bloku icra olunur, yoxsa dövrə dayanır.
Dövrə başlamazdan əvvəl dəyişən adətən xaricdə təyin edilir, və şərtə uyğun olaraq yenilənmə də kod bloku daxilində aparılır.

content.code:
#include <iostream>

int main() {
  int counter = 1;
  while (counter <= 5) {
    std::cout << "Number: " << counter << std::endl;
    counter++;
  }
  return 0;
}
// Output:
// Number: 1
// Number: 2
// Number: 3
// Number: 4
// Number: 5

#include <iostream>

int main() {
  int i = 1;
  while (i <= 3) {
    int j = 1;
    while (j <= 3) {
      std::cout << "(" << i << "," << j << ") ";
      j++;
    }
    std::cout << std::endl;
    i++;
  }
  return 0;
}
// Output:
// (1,1) (1,2) (1,3)
// (2,1) (2,2) (2,3)
// (3,1) (3,2) (3,3)

#include <iostream>

int main() {
  int sum = 0;
  int i = 1;
  while (i <= 4) {
    sum += i;
    i++;
  }
  std::cout << "Sum: " << sum << std::endl;
  return 0;
}
// Output:
// Sum: 10

